const today = new Date();
const fmt = d => d.toISOString().split('T')[0];
const daysAgo = (n) => { const d = new Date(today); d.setDate(d.getDate() - n); return fmt(d); };

const queries = [
  { name: 'last_7d_total',  body: { startDate: daysAgo(8),  endDate: daysAgo(2),  dataState: 'final' } },
  { name: 'prior_7d_total', body: { startDate: daysAgo(15), endDate: daysAgo(9),  dataState: 'final' } },
  { name: 'last_28d_total', body: { startDate: daysAgo(29), endDate: daysAgo(2),  dataState: 'final' } },
  { name: 'top_pages_7d',     body: { startDate: daysAgo(8),  endDate: daysAgo(2), dimensions: ['page'],  rowLimit: 50, dataState: 'final' } },
  { name: 'top_pages_prior',  body: { startDate: daysAgo(15), endDate: daysAgo(9), dimensions: ['page'],  rowLimit: 50, dataState: 'final' } },
  { name: 'top_queries_7d',   body: { startDate: daysAgo(8),  endDate: daysAgo(2), dimensions: ['query'], rowLimit: 25, dataState: 'final' } }
];

return queries.map(q => ({ json: { name: q.name, gsc_query_json: JSON.stringify(q.body), week_start: daysAgo(8), week_end: daysAgo(2) } }));

const responses = $input.all();
const names = $('Build Queries').all();
const r = {};
for (let i = 0; i < responses.length; i++) {
  r[names[i].json.name] = responses[i].json;
}
const weekStart = names[0].json.week_start;
const weekEnd   = names[0].json.week_end;

const last  = (r.last_7d_total?.rows || [{}])[0]  || {};
const prior = (r.prior_7d_total?.rows || [{}])[0] || {};
const last28 = (r.last_28d_total?.rows || [{}])[0] || {};

const lastImp  = last.impressions  || 0;
const lastClk  = last.clicks       || 0;
const lastCtr  = last.ctr          || 0;
const lastPos  = last.position     || 0;
const priorImp = prior.impressions || 0;
const priorClk = prior.clicks      || 0;
const priorCtr = prior.ctr         || 0;
const priorPos = prior.position    || 0;

const dImp = lastImp - priorImp;
const dClk = lastClk - priorClk;
const dPos = priorPos > 0 ? (priorPos - lastPos) : 0;
const pctImp = priorImp > 0 ? Math.round((dImp / priorImp) * 100) : 0;

// Pages tracking
const lastPages  = (r.top_pages_7d?.rows || []).map(row => ({ url: row.keys[0], imp: row.impressions, clk: row.clicks, ctr: row.ctr, pos: row.position }));
const priorPages = (r.top_pages_prior?.rows || []);
const priorByUrl = {};
for (const row of priorPages) priorByUrl[row.keys[0]] = { pos: row.position, clk: row.clicks };

const pagesEnriched = lastPages.map(p => {
  const prev = priorByUrl[p.url];
  const dposPage = prev ? (prev.pos - p.pos) : null;
  const dclkPage = prev ? (p.clk - prev.clk) : null;
  return { ...p, delta_pos: dposPage, delta_clk: dclkPage };
});

const winners = pagesEnriched
  .filter(p => p.delta_pos !== null && p.delta_pos > 0)
  .sort((a, b) => b.delta_pos - a.delta_pos)
  .slice(0, 3);

const losers = pagesEnriched
  .filter(p => p.delta_pos !== null && p.delta_pos < -1)
  .sort((a, b) => a.delta_pos - b.delta_pos)
  .slice(0, 3);

// New queries (in last 7d top, not in prior 7d top — approximation)
const lastQueries  = (r.top_queries_7d?.rows || []).map(row => ({ q: row.keys[0], imp: row.impressions, pos: row.position }));
// We don't fetch prior queries for new detection cost — flag those with impressions >= 5
const newishQueries = lastQueries.filter(q => q.imp >= 5).slice(0, 5);

// Concentration alert: if top page accounts for >25% of impressions
const topPage = pagesEnriched[0];
const topPagePct = lastImp > 0 && topPage ? Math.round((topPage.imp / lastImp) * 100) : 0;

// Build Telegram message (Markdown)
const fmtPct = (n) => (n >= 0 ? '+' : '') + n + '%';
const fmtSign = (n) => (n >= 0 ? '+' : '') + n;
const fmtPos = (n) => Number(n).toFixed(1);
const slugUrl = (url) => url.replace('https://bigotescaninos.com', '').slice(0, 60);

const lines = [
  '📊 *GSC Weekly* — ' + weekStart + ' a ' + weekEnd,
  '',
  '*WoW (vs sem anterior):*',
  '   Impresiones: ' + priorImp + ' → ' + lastImp + ' (' + fmtPct(pctImp) + ')',
  '   Clicks: ' + priorClk + ' → ' + lastClk + ' (' + fmtSign(dClk) + ')',
  '   CTR: ' + (priorCtr * 100).toFixed(2) + '% → ' + (lastCtr * 100).toFixed(2) + '%',
  '   Pos avg: ' + fmtPos(priorPos) + ' → ' + fmtPos(lastPos) + ' (' + fmtSign(Math.round(dPos * 10) / 10) + ')',
  '',
  '*Últimos 28d (contexto):* ' + (last28.impressions || 0) + ' imp, ' + (last28.clicks || 0) + ' clk, pos ' + fmtPos(last28.position || 0)
];

if (winners.length > 0) {
  lines.push('', '🏆 *Top ganadores (Δ pos):*');
  for (const w of winners) lines.push('   • ' + slugUrl(w.url) + ' — pos ' + fmtPos(w.pos) + ' (' + fmtSign(Math.round(w.delta_pos * 10) / 10) + ')');
}

if (losers.length > 0) {
  lines.push('', '🔻 *Top perdedores:*');
  for (const l of losers) lines.push('   • ' + slugUrl(l.url) + ' — pos ' + fmtPos(l.pos) + ' (' + fmtSign(Math.round(l.delta_pos * 10) / 10) + ')');
}

if (newishQueries.length > 0) {
  lines.push('', '🆕 *Top queries semana:*');
  for (const q of newishQueries) lines.push('   • "' + q.q + '" — ' + q.imp + ' imp pos ' + fmtPos(q.pos));
}

if (topPagePct >= 25) {
  lines.push('', '⚠️ *Concentración:* top page ' + topPagePct + '% de impresiones (' + slugUrl(topPage.url) + ')');
}

const telegram_message = lines.join('\n');

// Build sheet append payloads
const trackingRow = [weekStart, weekEnd, lastImp, lastClk, lastCtr.toFixed(4), lastPos.toFixed(2), dImp, dClk, dPos.toFixed(2)];
const trackingAppendJson = JSON.stringify({
  values: [trackingRow]
});

const pagesRows = pagesEnriched.slice(0, 30).map(p => [
  weekStart,
  p.url,
  p.imp,
  p.clk,
  p.ctr.toFixed(4),
  p.pos.toFixed(2),
  p.delta_pos !== null ? p.delta_pos.toFixed(2) : '',
  p.delta_clk !== null ? p.delta_clk : ''
]);
const pagesAppendJson = JSON.stringify({ values: pagesRows });

return [{
  json: {
    telegram_message,
    tracking_append_json: trackingAppendJson,
    pages_append_json: pagesAppendJson,
    summary: { week_start: weekStart, last_imp: lastImp, last_clk: lastClk, delta_imp_pct: pctImp, delta_pos: Math.round(dPos * 10) / 10 }
  }
}];
